import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const DEMO = {
  admin: { email: 'admin@college.edu', password: 'Admin@123' },
  student: { email: 'student@college.edu', password: 'Student@123' },
};

export default function Login() {
  const [role, setRole] = useState('student');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login, logout } = useAuth();
  const navigate = useNavigate();

  const switchRole = (r) => {
    setRole(r);
    setEmail('');
    setPassword('');
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const data = await login(email, password);
      if (role === 'admin' && data.user.role !== 'admin') {
        logout();
        setError('This account does not have administrator access.');
        return;
      }
      if (role === 'student' && data.user.role !== 'student') {
        logout();
        setError('This account does not have student access.');
        return;
      }
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-panel-brand">
        <div className="brand-logo">CB</div>
        <h1>Campus Bus Services</h1>
        <p className="brand-tagline">Transportation Fee Portal</p>
        <div className="brand-footer">
          <span>Secure access for students and administrators</span>
        </div>
      </div>

      <div className="login-panel-form">
        <div className="login-card">
          <div className="login-card-header">
            <h2>Sign In</h2>
            <p>Enter your credentials to access the portal</p>
          </div>

          <div className="role-tabs">
            <button type="button" className={`role-tab ${role === 'student' ? 'active' : ''}`} onClick={() => switchRole('student')}>
              Student
            </button>
            <button type="button" className={`role-tab ${role === 'admin' ? 'active' : ''}`} onClick={() => switchRole('admin')}>
              Administrator
            </button>
          </div>

          {error && <div className="login-error">{error}</div>}

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Email</label>
              <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="name@college.edu" required autoComplete="email" />
            </div>
            <div className="form-group">
              <label>Password</label>
              <div className="input-wrap">
                <input type={showPass ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="Enter password" required autoComplete="current-password" />
                <button type="button" className="toggle-pass" onClick={() => setShowPass(!showPass)} aria-label="Toggle password">
                  {showPass ? 'Hide' : 'Show'}
                </button>
              </div>
            </div>
            <button type="submit" className="btn btn-primary btn-lg login-submit" disabled={loading}>
              {loading ? <><span className="spinner spinner-sm" /> Signing in...</> : 'Sign In'}
            </button>
          </form>

          <details className="demo-details">
            <summary>Demo credentials</summary>
            <div className="demo-cred-list">
              <div>
                <span>Student</span>
                <code>{DEMO.student.email}</code>
                <code>{DEMO.student.password}</code>
              </div>
              <div>
                <span>Admin</span>
                <code>{DEMO.admin.email}</code>
                <code>{DEMO.admin.password}</code>
              </div>
            </div>
          </details>
        </div>
      </div>
    </div>
  );
}
